import { useState, useEffect } from 'react';
import { Link, NavLink, useLocation } from 'react-router-dom';
import { Menu, X, Shield, LogIn } from 'lucide-react';

const LINKS = [
  {to:'/',l:'Home'},{to:'/about',l:'About'},{to:'/services',l:'Services'},
  {to:'/blog',l:'Blog'},{to:'/team',l:'Team'},{to:'/announcements',l:'News'},
  {to:'/careers',l:'Careers'},{to:'/contact',l:'Contact'},
];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);
  const loc = useLocation();

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', fn, { passive: true });
    fn();
    return () => window.removeEventListener('scroll', fn);
  }, []);

  useEffect(() => { setOpen(false); }, [loc]);
  useEffect(() => {
    document.body.style.overflow = open ? 'hidden' : '';
    return () => { document.body.style.overflow = ''; };
  }, [open]);

  // Pages with dark hero images — navbar can be transparent at top
  const darkHeroPages = ['/', '/about', '/services', '/blog', '/team', '/announcements', '/careers', '/contact', '/certificate-verification'];
  const hasDarkHero = darkHeroPages.includes(loc.pathname);

  // Transparent only when: page has dark hero AND not scrolled AND drawer not open
  const isTransparent = hasDarkHero && !scrolled && !open;

  return (
    <>
      <nav style={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000, height: 64,
        background: isTransparent ? 'transparent' : 'rgba(255,255,255,0.98)',
        backdropFilter: isTransparent ? 'none' : 'blur(16px)',
        borderBottom: isTransparent ? '1px solid transparent' : '1px solid var(--rule)',
        transition: 'background 0.3s ease, border-color 0.3s ease',
        boxShadow: isTransparent ? 'none' : '0 1px 12px rgba(0,0,0,0.06)',
      }}>
        <div style={{ maxWidth: 1160, margin: '0 auto', padding: '0 20px', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12 }}>

          {/* Logo */}
          <Link to="/" style={{ display: 'flex', flexDirection: 'column', flexShrink: 0, textDecoration: 'none' }}>
            <span style={{
              fontFamily: 'var(--serif)', fontSize: '1.25rem', fontWeight: 800, lineHeight: 1,
              letterSpacing: '-0.02em', transition: 'color 0.3s',
              color: isTransparent ? '#ffffff' : 'var(--ink)',
            }}>SYNNOVIQ</span>
            <span style={{
              fontSize: '0.5rem', fontWeight: 700, letterSpacing: '0.22em',
              textTransform: 'uppercase', marginTop: 2, transition: 'color 0.3s',
              color: isTransparent ? 'rgba(255,255,255,0.55)' : 'var(--blue)',
            }}>Technologies</span>
          </Link>

          {/* Desktop links */}
          <ul style={{ display: 'flex', gap: 2, listStyle: 'none', flex: 1, justifyContent: 'center' }} className="hide-mobile">
            {LINKS.map(({ to, l }) => (
              <li key={to}>
                <NavLink to={to} end={to === '/'} style={({ isActive }) => ({
                  display: 'block', padding: '6px 11px', borderRadius: 6,
                  fontSize: '0.82rem', fontWeight: isActive ? 600 : 500,
                  transition: 'color 0.2s',
                  color: isActive
                    ? 'var(--blue)'
                    : isTransparent ? 'rgba(255,255,255,0.82)' : 'var(--ink60)',
                })}
                  onMouseEnter={e => { e.currentTarget.style.color = 'var(--blue)'; }}
                  onMouseLeave={e => { e.currentTarget.style.color = ''; }}
                >{l}</NavLink>
              </li>
            ))}
          </ul>

          {/* Desktop actions */}
          <div style={{ display: 'flex', gap: 8, flexShrink: 0 }} className="hide-mobile">
            <Link to="/certificate-verification" style={{
              display: 'flex', alignItems: 'center', gap: 5,
              padding: '7px 13px', borderRadius: 8, fontSize: '0.76rem', fontWeight: 500,
              transition: 'all 0.2s', border: '1px solid',
              borderColor: isTransparent ? 'rgba(255,255,255,0.3)' : 'var(--rule)',
              color: isTransparent ? 'rgba(255,255,255,0.75)' : 'var(--ink40)',
            }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = 'var(--blue)'; e.currentTarget.style.color = 'var(--blue)'; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = ''; e.currentTarget.style.color = ''; }}
            ><Shield size={12} /> Verify</Link>
            <Link to="/login" className="btn btn-blue" style={{ padding: '7px 16px', fontSize: '0.78rem' }}>
              <LogIn size={12} /> Login
            </Link>
          </div>

          {/* Hamburger — mobile only */}
          <button
            onClick={() => setOpen(!open)}
            className="hide-desktop"
            aria-label={open ? 'Close menu' : 'Open menu'}
            style={{
              width: 40, height: 40, display: 'flex', alignItems: 'center', justifyContent: 'center',
              borderRadius: 8, border: '1px solid', transition: 'all 0.2s',
              borderColor: isTransparent ? 'rgba(255,255,255,0.35)' : 'var(--rule)',
              color: isTransparent ? '#fff' : 'var(--ink)',
              background: 'transparent',
            }}
          >
            {open ? <X size={18} /> : <Menu size={18} />}
          </button>
        </div>
      </nav>

      {/* Mobile full-screen drawer */}
      <div style={{
        position: 'fixed', inset: 0, zIndex: 999,
        background: 'rgba(4,10,20,0.98)', backdropFilter: 'blur(20px)',
        display: 'flex', flexDirection: 'column',
        padding: '84px 28px 40px',
        transform: open ? 'translateX(0)' : 'translateX(100%)',
        transition: 'transform 0.32s cubic-bezier(0.4,0,0.2,1)',
        overflowY: 'auto',
      }}>
        {LINKS.map(({ to, l }, i) => (
          <NavLink key={to} to={to} end={to === '/'} style={({ isActive }) => ({
            display: 'block', padding: '17px 0',
            fontFamily: 'var(--serif)', fontSize: '1.9rem', fontWeight: 800,
            letterSpacing: '-0.02em', color: isActive ? 'var(--blue)' : '#fff',
            borderBottom: '1px solid rgba(255,255,255,0.07)',
            animationName: 'drawerFadeUp',
            animationDuration: '0.4s',
            animationDelay: `${i * 0.05}s`,
            animationFillMode: 'both',
          })}>{l}</NavLink>
        ))}
        <div style={{ display: 'flex', gap: 12, marginTop: 32 }}>
          <Link to="/certificate-verification" className="btn btn-ghost" style={{ flex: 1, justifyContent: 'center', padding: '12px' }}>
            <Shield size={14} /> Verify
          </Link>
          <Link to="/login" className="btn btn-blue" style={{ flex: 1, justifyContent: 'center', padding: '12px' }}>
            <LogIn size={14} /> Login
          </Link>
        </div>
      </div>

      <style>{`
        @keyframes drawerFadeUp {
          from { opacity: 0; transform: translateY(14px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        @media (max-width: 767px)  { .hide-mobile  { display: none !important; } }
        @media (min-width: 768px)  { .hide-desktop { display: none !important; } }
      `}</style>
    </>
  );
}
